from pathlib import Path
from subprocess import check_output, CalledProcessError

def parse_fasta(path):
    seqs={}
    name=None
    buf=[]
    for line in Path(path).read_text().splitlines():
        if line.startswith('>'):
            if name is not None:
                seqs[name]=''.join(buf).strip().lower()
            name=line[1:].strip()
            buf=[]
        else:
            buf.append(line.strip())
    if name is not None:
        seqs[name]=''.join(buf).strip().lower()
    return seqs

def rc(seq):
    return seq.translate(str.maketrans('acgt','tgca'))[::-1]

def tm(seq):
    out=check_output(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq], text=True)
    return float(out.strip())

seqs=parse_fasta('/app/sequences.fasta')
inp=seqs['input']
out=seqs['output']
p=0
while p<min(len(inp),len(out)) and inp[p]==out[p]:
    p+=1
s=0
while s<min(len(inp)-p,len(out)-p) and inp[-1-s]==out[-1-s]:
    s+=1
insert=out[p:len(out)-s]
print('split',p,'insert_len',len(insert),insert)
found=[]
for k in range(1,len(insert)):
    A=insert[:k]
    B=insert[k:]
    for lr in range(15,37):
        if lr>p: continue
        annealed_rev=inp[p-lr:p]
        try:
            tm_r=tm(annealed_rev)
        except CalledProcessError:
            continue
        if not (58<=tm_r<=72):
            continue
        rev_primer=rc(A)+rc(annealed_rev)
        for lf in range(15,37):
            if p+lf>len(inp): continue
            annealed_fwd=inp[p:p+lf]
            try:
                tm_f=tm(annealed_fwd)
            except CalledProcessError:
                continue
            if not (58<=tm_f<=72):
                continue
            if abs(tm_f-tm_r)>5:
                continue
            fwd_primer=B+annealed_fwd
            concat=rc(rev_primer)+fwd_primer
            idx=concat.find(insert)
            if idx==-1:
                continue
            ar=concat[:idx]
            af=concat[idx+len(insert):]
            if ar!=annealed_rev or af!=annealed_fwd:
                continue
            if not (15<=len(ar)<=45 and 15<=len(af)<=45):
                continue
            found.append((max(len(fwd_primer),len(rev_primer)), abs(tm_f-tm_r), len(fwd_primer)+len(rev_primer), k, lr, lf, tm_r, tm_f, fwd_primer, rev_primer, ar, af))
found.sort()
print('candidates',len(found))
for item in found[:25]:
    mx, d, total, k, lr, lf, tm_r, tm_f, fwd, rev, ar, af = item
    print({'k':k,'lr':lr,'lf':lf,'tm_r':round(tm_r,2),'tm_f':round(tm_f,2),'delta':round(d,2),'fwd_len':len(fwd),'rev_len':len(rev),'fwd':fwd,'rev':rev})
